import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.ActorMaterializer
import akka.util.ByteString
import scala.concurrent.Future
import scala.util.{Failure, Success}
import java.net.{InetAddress, URI}

object WebhookProxyService extends App {
  implicit val system = ActorSystem("webhook-proxy-service")
  implicit val materializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher

  val allowlist = Set("example.com", "partnerapi.com")

  def isAllowedHost(uri: URI): Boolean = {
    val host = uri.getHost
    allowlist.contains(host)
  }

  def isSafeAddress(address: InetAddress): Boolean = {
    !address.isLoopbackAddress &&
    !address.isLinkLocalAddress &&
    !address.isSiteLocalAddress &&
    !address.isMulticastAddress
  }

  def fetchContent(url: String): Future[HttpResponse] = {
    val uri = new URI(url)
    if (!isAllowedHost(uri)) {
      Future.failed(new IllegalArgumentException("Host not allowed"))
    } else {
      val address = InetAddress.getByName(uri.getHost)
      if (!isSafeAddress(address)) {
        Future.failed(new IllegalArgumentException("Unsafe address"))
      } else {
        Http().singleRequest(HttpRequest(uri = url))
      }
    }
  }

  val route =
    path("fetch") {
      post {
        entity(as[String]) { url =>
          onComplete(fetchContent(url)) {
            case Success(response) =>
              complete(response.entity.dataBytes.runFold(ByteString(""))(_ ++ _).map(_.utf8String))
            case Failure(ex) =>
              complete(HttpResponse(StatusCodes.BadRequest, entity = ex.getMessage))
